  1734в†’## 4.4 PM Scheduler (Tactical)
  1735в†’
  1736в†’### 4.4.1 Purpose
  1737в†’
  1738в†’Schedule preventive maintenance for the 12-week tactical horizon, respecting track availability, labor capacity, and material constraints.
  1739в†’
  1740в†’### 4.4.2 Implementation
  1741в†’
  1742в†’```typescript
  1743в†’interface TacticalSchedulerConfig {
  1744в†’  horizonWeeks: number;           // 12
  1745в†’  materialCheckDaysHard: number;  // 14 (hard constraint)
  1746в†’  materialCheckDaysSoft: number;  // 90 (soft constraint)
  1747в†’  trackUtilizationTarget: number; // 0.85
  1748в†’}
  1749в†’
  1750в†’class TacticalPMScheduler {
  1751в†’  async schedule(depotId: string): Promise<SchedulingResult> {
  1752в†’    const config = this.config;
  1753в†’    const horizonEnd = addWeeks(new Date(), config.horizonWeeks);
  1754в†’    
  1755в†’    // 1. Get pending PMs that need scheduling
  1756в†’    const pendingPMs = await this.getPendingPMs(depotId, horizonEnd);
  1757в†’    
  1758в†’    // 2. Get resource availability
  1759в†’    const trackAvailability = await this.getTrackAvailability(depotId, horizonEnd);
  1760в†’    const laborCapacity = await this.getLaborCapacity(depotId, horizonEnd);
  1761в†’    const materialPositions = await this.getMaterialPositions(depotId);
  1762в†’    
  1763в†’    // 3. Sort PMs by priority (urgency, criticality)
  1764в†’    const sortedPMs = this.prioritizePMs(pendingPMs);
  1765в†’    
  1766в†’    // 4. Schedule each PM
  1767в†’    const scheduled: ScheduledPM[] = [];
  1768в†’    const deferred: DeferredPM[] = [];
